1	const countBy = <T>(items: T[], keyFn: (item: T) => string): Record<string, number> => {
2	  const counts: Record<string, number> = {};
3	  for (const item of items) {
4	    const key = keyFn(item);
5	    counts[key] = (counts[key] ?? 0) + 1;
6	  }
7	  return counts;
8	};
9	
10	const PROCESSING_FEE = 5;
11	
12	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	};
18	
19	const COMPONENT_PREMIUM = 25;
20	const COMPONENT_BLOCK_PREMIUM = 60;
21	const COMPONENT_BLOCK_SIZE = 3;
22	
23	const KNOWN_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	
25	const isMainItem = (type: string): boolean => MAIN_ITEM_PREMIUMS.hasOwnProperty(type);
26	
27	const isComponent = (type: string): boolean => !isMainItem(type);
28	
29	const isKnownType = (type: string): boolean =>
30	  isMainItem(type) || KNOWN_COMPONENT_TYPES.has(type);
31	
32	const CURSED_SURCHARGE_RATE = 0.5;
33	const HIGH_ENCHANTMENT_THRESHOLD = 5;
34	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
35	
36	const calculateItemSurcharges = (item: { type: string; cursed?: boolean; enchantment?: number }): number => {
37	  const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
38	  const curseSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
39	  const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
40	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
41	    : 0;
42	  return curseSurcharge + enchantmentSurcharge;
43	};
44	
45	const calculateComponentGroupPremium = (count: number): number =>
46	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
47	
48	const INSURANCE_VALUES: Record<string, number> = {
49	  sword: 1000,
50	  amulet: 600,
51	  staff: 800,
52	  potion: 400,
53	};
54	const COMPONENT_INSURANCE_VALUE = 250;
55	const DEDUCTIBLE = 100;
56	
57	const getInsuranceValue = (type: string): number =>
58	  INSURANCE_VALUES[type] ?? COMPONENT_INSURANCE_VALUE;
59	
60	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
61	const CLAIM_HIGH_ENCHANTMENT_RATE = 0.5;
62	
63	const calculateClaimPayout = (
64	  damages: { itemType: string; amount: number }[],
65	  remainingCap: number,
66	  policyItems: any[],
67	): { payout: number; remainingCap: number } => {
68	  let totalPayout = 0;
69	  for (const damage of damages) {
70	    const policyItem = policyItems.find((item: any) => item.type === damage.itemType);
71	    const enchantment = policyItem?.enchantment ?? 0;
72	    const reimbursement = enchantment >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD
73	      ? damage.amount * CLAIM_HIGH_ENCHANTMENT_RATE
74	      : damage.amount;
75	    totalPayout += Math.max(0, reimbursement - DEDUCTIBLE);
76	  }
77	  if (totalPayout > remainingCap) {
78	    totalPayout = remainingCap;
79	  }
80	  return { payout: Math.floor(totalPayout), remainingCap: remainingCap - totalPayout };
81	};
82	
83	const validateDamagesAgainstPolicy = (
84	  damages: { itemType: string }[],
85	  policyItems: { type: string }[],
86	): void => {
87	  const damageCounts = countBy(damages, (d) => d.itemType);
88	  const policyCounts = countBy(policyItems, (item) => item.type);
89	  for (const [type, count] of Object.entries(damageCounts)) {
90	    if (count > (policyCounts[type] ?? 0)) {
91	      throw new Error(`More damages of type ${type} than policy covers`);
92	    }
93	  }
94	};
95	
96	const FIRST_INSURANCE_RATE = 0.1;
97	const LOYALTY_DISCOUNT_RATE = 0.2;
98	const LOYALTY_THRESHOLD_YEARS = 2;
99	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
100	
101	const calculatePremium = (items: { type: string; cursed?: boolean; enchantment?: number }[], yearsWithMHPCO: number, isFollowUp: boolean): number => {
102	  for (const item of items) {
103	    if (!isKnownType(item.type)) {
104	      throw new Error(`Unknown item type: ${item.type}`);
105	    }
106	  }
107	
108	  let policyBasePremium = 0;
109	  let itemSurcharges = 0;
110	
111	  for (const item of items) {
112	    if (!isComponent(item.type)) {
113	      policyBasePremium += MAIN_ITEM_PREMIUMS[item.type] ?? 0;
114	      itemSurcharges += calculateItemSurcharges(item);
115	    }
116	  }
117	
118	  const componentCounts = countBy(items.filter((item) => isComponent(item.type)), (item) => item.type);
119	  for (const count of Object.values(componentCounts)) {
120	    policyBasePremium += calculateComponentGroupPremium(count);
121	  }
122	
123	  const policyModifierRate = FIRST_INSURANCE_RATE
124	    - (yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0)
125	    - (isFollowUp ? FOLLOW_UP_DISCOUNT_RATE : 0);
126	  const policyModifiers = policyBasePremium * policyModifierRate;
127	
128	  return Math.ceil(policyBasePremium + itemSurcharges + policyModifiers + PROCESSING_FEE);
129	};
