131	export function processScenario(scenario: { customer: { yearsWithMHPCO: number }; steps: any[] }): { results: unknown[] } {
132	  let quoteCount = 0;
133	  const policies: Map<number, { items: any[]; remainingCap: number }> = new Map();
134	
135	  const results = scenario.steps.map((step, index) => {
136	    if (step.op === "quote") {
137	      const isFollowUp = quoteCount > 0;
138	      quoteCount++;
139	      const items = step.items ?? [];
140	      const premium = calculatePremium(items, scenario.customer.yearsWithMHPCO, isFollowUp);
141	      const insuranceSum = items.reduce((sum: number, item: any) => sum + getInsuranceValue(item.type), 0);
142	      policies.set(index, { items, remainingCap: insuranceSum * 2 });
143	      return { premium };
144	    } else {
145	      const policy = policies.get(step.policy)!;
146	      for (const damage of step.incident.damages) {
147	        if (damage.amount < 0) {
148	          throw new Error(`Negative damage amount: ${damage.amount}`);
149	        }
150	      }
151	      validateDamagesAgainstPolicy(step.incident.damages, policy.items);
152	      const claimResult = calculateClaimPayout(step.incident.damages, policy.remainingCap, policy.items);
153	      policy.remainingCap = claimResult.remainingCap;
154	      return claimResult;
155	    }
156	  });
157	  return { results };
158	}
