102	  for (const item of items) {
103	    if (!isKnownType(item.type)) {
104	      throw new Error(`Unknown item type: ${item.type}`);
105	    }
106	  }
107	
108	  let policyBasePremium = 0;
109	  let itemSurcharges = 0;
110	
111	  for (const item of items) {
112	    if (isMainItem(item.type)) {
113	      policyBasePremium += MAIN_ITEM_PREMIUMS[item.type] ?? 0;
114	      itemSurcharges += calculateItemSurcharges(item);
115	    }
116	  }
117	
118	  const componentCounts = countBy(items.filter((item) => isComponent(item.type)), (item) => item.type);
119	  for (const count of Object.values(componentCounts)) {
120	    policyBasePremium += calculateComponentGroupPremium(count);
